// Recebe payload do dashboard e monta os campos do evento
const raw = $input.first().json.body || $input.first().json;

const data = String(raw.data || '').trim();
const horario = String(raw.horario || '').trim();
const qtd = Number(raw.qtd_pessoas || 0);
const email = String(raw.cliente_email || '').trim();
const observ = String(raw.observacoes || '').trim();

// Start/End ISO no fuso Manaus (UTC-4, sem horário de verão)
const startIso = `${data}T${horario}:00-04:00`;
const [h, m] = horario.split(':').map(Number);
const endMinutes = h * 60 + m + 90; // duração 1h30
const endH = String(Math.floor(endMinutes / 60) % 24).padStart(2, '0');
const endM = String(endMinutes % 60).padStart(2, '0');
const endIso = `${data}T${endH}:${endM}:00-04:00`;

const desc = [
  `Cliente: ${raw.cliente_nome}`,
  `Telefone: ${raw.cliente_telefone}`,
  email ? `Email: ${email}` : null,
  `Área: ${raw.area}`,
  `Pessoas: ${qtd}`,
  observ ? `Obs: ${observ}` : null,
].filter(Boolean).join('\n');

return [{
  json: {
    start_iso: startIso,
    end_iso: endIso,
    summary: `Reserva LVN — ${raw.cliente_nome} (${qtd}p)`,
    description: desc,
    location: `La Vaca Negra · ${raw.area}`,
  }
}];
